class Solution {
    public int maxScore(int[] nums) {
        int n = nums.length / 2;
        int mask = 1 << nums.length;
        int[] memo = new int[mask];
        Arrays.fill(memo, -1);
        return backtrack(nums, n, 0, 0, memo);
    }

    private int backtrack(int[] nums, int n, int i, int mask, int[] memo) {
        if (memo[mask] != -1) return memo[mask];
        if (i > n) return 0;
        int maxScore = 0;
        for (int j = 0; j < nums.length; j++) {
            if ((mask & (1 << j)) == 0) {
                for (int k = j + 1; k < nums.length; k++) {
                    if ((mask & (1 << k)) == 0) {
                        int newMask = mask | (1 << j) | (1 << k);
                        maxScore = Math.max(maxScore, i * gcd(nums[j], nums[k]) + backtrack(nums, n, i + 1, newMask, memo));
                    }
                }
            }
        }
        return memo[mask] = maxScore;
    }

    private int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
